DROP TABLE IF EXISTS `pts_inventory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pts_inventory` (
  `id` int NOT NULL AUTO_INCREMENT,
  `pts_demand_id` int NOT NULL,
  `spare_id` int DEFAULT NULL,
  `tool_id` int DEFAULT NULL,
  `box_no` varchar(100) DEFAULT NULL,
  `quantity` int NOT NULL DEFAULT '1',
  `status` enum('issued','replaced','surveyed') DEFAULT 'issued',
  `issued_date` date DEFAULT NULL,
  `replaced_date` date DEFAULT NULL,
  `surveyed_date` date DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_pts_inventory_demand` (`pts_demand_id`),
  CONSTRAINT `fk_pts_inventory_demand` FOREIGN KEY (`pts_demand_id`) REFERENCES `pts_special_demand` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
