DROP TABLE IF EXISTS `stock_update`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stock_update` (
  `id` int NOT NULL AUTO_INCREMENT,
  `spare_id` int DEFAULT NULL,
  `tool_id` int DEFAULT NULL,
  `box_no` json DEFAULT NULL,
  `stocked_in_qty` int NOT NULL,
  `mo_no` varchar(25) DEFAULT NULL,
  `mo_date` date DEFAULT NULL,
  `issue_date` date NOT NULL,
  `return_date` date DEFAULT NULL,
  `qty_received` int NOT NULL DEFAULT '0',
  `created_by` int NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `approved_by` int DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `status` varchar(20) DEFAULT 'pending',
  `issued_id` int DEFAULT NULL,
  `transaction_id` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_stock_update_spare` (`spare_id`),
  KEY `fk_stock_update_tool` (`tool_id`),
  KEY `fk_stock_update_created_by` (`created_by`),
  KEY `fk_stock_update_approved_by` (`approved_by`),
  CONSTRAINT `fk_stock_update_approved_by` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_stock_update_created_by` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_stock_update_spare` FOREIGN KEY (`spare_id`) REFERENCES `spares` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_stock_update_tool` FOREIGN KEY (`tool_id`) REFERENCES `tools` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=49 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

