--
-- Table structure for table `ty_loan`
--

DROP TABLE IF EXISTS `ty_loan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ty_loan` (
  `id` int NOT NULL AUTO_INCREMENT,
  `transaction_id` varchar(25) NOT NULL,
  `spare_id` int DEFAULT NULL,
  `tool_id` int DEFAULT NULL,
  `qty_withdrawn` int NOT NULL,
  `service_no` varchar(100) NOT NULL,
  `concurred_by` varchar(150) NOT NULL,
  `issue_date` date NOT NULL,
  `loan_duration` int DEFAULT NULL,
  `return_date` date DEFAULT NULL,
  `box_no` json NOT NULL,
  `qty_received` int DEFAULT NULL,
  `created_by` int NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `approved_by` int DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `status` varchar(10) DEFAULT 'pending',
  `unit_name` varchar(150) DEFAULT NULL,
  `individual_name` varchar(150) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `designation` varchar(150) DEFAULT NULL,
  `remarks` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_ty_loan_spare` (`spare_id`),
  KEY `fk_ty_loan_tool` (`tool_id`),
  KEY `fk_ty_loan_created_by` (`created_by`),
  KEY `fk_ty_loan_approved_by` (`approved_by`),
  CONSTRAINT `fk_ty_loan_approved_by` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_ty_loan_created_by` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_ty_loan_spare` FOREIGN KEY (`spare_id`) REFERENCES `spares` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_ty_loan_tool` FOREIGN KEY (`tool_id`) REFERENCES `tools` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=100 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

